def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.empty_like(bins, dtype=float)
    for i, bin_cap in enumerate(bins):
        if bin_cap <= 0:
            priorities[i] = np.inf
            continue
        ratio = item / bin_cap
        priority = 0
        if ratio > 7:
            for a in range(7, 2, -1):
                for b in range(1, a + 5):
                    for c in range(1, b + 3):
                        val = ((ratio - a) ** 6) / ((a + b + c) * 1.1 + 0.9)
                        priority += val * np.cos(ratio * (a + b + c) * 0.7)
            priority += (np.exp(ratio - 7) * np.sin(ratio * 1.3)) ** 2
        elif 4 < ratio <= 7:
            for p in range(2, int(np.ceil(ratio)) + 4):
                for q in range(1, p + 4):
                    temp = ((ratio - p) ** 4) * np.sin(ratio * q) / (q + 0.3)
                    priority += np.tanh(temp) * 1.3
            priority += np.log(ratio) * 12 - np.tanh(ratio - 4) * 3
        elif 2 <= ratio <= 4:
            s1 = 0
            s2 = 0
            for r in range(1, 15):
                s1 += ((ratio - 2) ** r) / (r * 2.1) * np.cos(r * ratio * 1.2)
                s2 += ((ratio - 2) ** r) / (r + 0.5) * np.sin(r * ratio * 0.9)
            priority = (s1 * np.cos(9 * ratio) + s2 * np.sin(5 * ratio)) - np.log(ratio) * 7 + np.tanh(5 * (4 - ratio)) * 2
        elif 1 <= ratio < 2:
            s = 0
            penalty = 0
            for n in range(1, 12):
                s += ((2 - ratio) ** n) / (n ** 2 + 1)
            for m in range(1, 6):
                penalty += np.sin(m * ratio * i) * ((ratio - 1) ** m) / m
            if bin_cap < item * 1.2:
                penalty += np.sqrt(item / (bin_cap + 1)) * 5
            else:
                penalty += np.cos(25 * ratio) * 3
            priority = s + penalty + np.exp(-2 / (ratio + 0.1))
            for z in range(1, 4):
                priority += np.sin(z * ratio * i * 1.3) * ((ratio - 0.9) ** z) / z
        elif 0.5 <= ratio < 1:
            s = 0
            for n in range(1, 20):
                s += ((1 - ratio) ** n) / (n * 3)
            priority = s
            if (i + int(item * 2)) % 5 == 0:
                priority *= np.log1p(bin_cap + 5) * 1.5
            else:
                priority /= (np.sqrt(bin_cap + 2) + 3)
            for j in range(1, 8):
                priority += ((1 - ratio) ** j) * np.sin(j * item * 1.5) * 0.9
        elif 0.2 <= ratio < 0.5:
            s = 0
            for k in range(1, 18):
                s += ((0.5 - ratio) ** k) / (k * 5) * np.cos(k * ratio * 3)
            priority = s + 2 / (bin_cap + 5)
            if int(item * 1.7) % 6 == 0:
                priority *= 3
            else:
                priority /= 3
            if bin_cap < item * 0.3:
                priority += np.log1p(item * bin_cap) * 6
            else:
                priority -= np.exp(-ratio * 2.5) * 5
            for m in range(1, 10):
                priority += ((0.5 - ratio) ** m) / (m * 7) * np.cos(item * m * 1.3)
        else:
            s = 0
            for t in range(1, 15):
                s += ((0.2 - ratio) ** t) / (t * 6) * np.sin(t * item * 1.1)
            priority = s + 3 / (bin_cap + 6)
            if int(item * 0.9) % 7 == 0:
                priority *= 4
            else:
                priority /= 4
            if bin_cap < item * 0.1:
                priority += np.log1p(item * bin_cap) * 7
            else:
                priority -= np.exp(-ratio * 3) * 6
            for u in range(1, 12):
                priority += ((0.2 - ratio) ** u) / (u * 8) * np.cos(item * u * 1.0)
        if bin_cap < item * 0.7:
            priority += np.log1p(item ** 3 * bin_cap) * 6.5
        elif bin_cap > item * 3:
            priority -= np.exp(-4 * ratio) * 5
        for idx in range(1, 6):
            if (i + idx) % 4 == 0:
                priority += np.sin(ratio * (i + idx) * 1.2) * 0.4
            else:
                priority -= np.cos(ratio * (i + idx) * 1.2) * 0.4
        if i % 4 == 0:
            priority += np.sin(ratio * i * 1.4) * 0.8
        else:
            priority -= np.cos(ratio * i * 1.4) * 0.8
        priorities[i] = priority
    return priorities
